import type { Metadata } from "next";
import StocktakeCount from "./StocktakeCount";

export const metadata: Metadata = {
  title: "実地棚卸 | ぐんじょうストア 在庫管理",
  description:
    "実地棚卸の照合画面。棚卸名・対象店舗・担当者・棚卸基準日と棚卸ステータス（準備中 / カウント中 / 差異確認中 / 確定）のヘッダ、棚ごとの進捗を持つロケーション（売場 / バックヤード / 棚番号）ナビ、理論在庫・実地カウント数・差異（= カウント − 理論、符号と色とアイコンで表示）・差異理由（棚卸差異 / 破損 / 紛失 / 入力ミス / 未入荷 …、差異≠0で必須）を編集できるカウント明細、バーコード / SKU スキャン入力で該当商品を加算、総差異点数・差異金額（原価 / 売価）・棚卸資産評価額をライブ集計する差異サマリー、カウント保存 / 差異確定 / 棚卸確定のアクションを備えた実地棚卸ツールです。",
};

export default function StocktakePage() {
  return <StocktakeCount />;
}

/**
 * Domain model + pure helpers for 実地棚卸 (physical inventory count).
 *
 * Kept framework-free so the reconciliation math (差異 / 差異金額 / 進捗) is unit
 * testable and the client component stays presentational.
 */

export type StocktakeStatus = "preparing" | "counting" | "reviewing" | "finalized"

/** 差異理由 — required whenever 差異 (counted − system) ≠ 0. */
export type VarianceReason =
  | "stocktake" // 棚卸差異 (原因特定できず)
  | "damage" // 破損
  | "loss" // 紛失・盗難
  | "input_error" // 入力ミス
  | "not_received" // 未入荷
  | "return" // 返品処理漏れ

export const VARIANCE_REASONS: { value: VarianceReason; label: string }[] = [
  { value: "stocktake", label: "棚卸差異" },
  { value: "damage", label: "破損" },
  { value: "loss", label: "紛失・盗難" },
  { value: "input_error", label: "入力ミス" },
  { value: "not_received", label: "未入荷" },
  { value: "return", label: "返品処理漏れ" },
]

export const VARIANCE_REASON_LABEL: Record<VarianceReason, string> = Object.fromEntries(
  VARIANCE_REASONS.map((r) => [r.value, r.label]),
) as Record<VarianceReason, string>

export interface CountItem {
  id: string
  /** ロケーション (棚) this item lives in. */
  locationId: string
  name: string
  sku: string
  jan: string
  /** 理論在庫 (system / book qty) — read-only. */
  systemQty: number
  /** 原価 (cost unit price, ¥). Variance amount is valued at cost. */
  unitCost: number
  /** 売価 (retail unit price, ¥) — shown for 評価額(売価) reference. */
  unitRetail: number
  /** 実地カウント数 — `null` = 未カウント (not yet counted). */
  countedQty: number | null
  /** 差異理由 — required when variance ≠ 0. */
  reason: VarianceReason | null
}

export interface Location {
  id: string
  name: string
  /** 売場 / バックヤード grouping for the section header. */
  zone: "sales_floor" | "backyard"
  shelfCode: string
}

export const LOCATIONS: Location[] = [
  { id: "loc-a1", name: "売場 A-1 (飲料)", zone: "sales_floor", shelfCode: "A-1" },
  { id: "loc-a2", name: "売場 A-2 (菓子)", zone: "sales_floor", shelfCode: "A-2" },
  { id: "loc-b1", name: "売場 B-1 (日用品)", zone: "sales_floor", shelfCode: "B-1" },
  { id: "loc-bk1", name: "バックヤード 棚1", zone: "backyard", shelfCode: "BK-1" },
  { id: "loc-bk2", name: "バックヤード 棚2", zone: "backyard", shelfCode: "BK-2" },
]

export const LOCATION_LABEL: Record<string, string> = Object.fromEntries(
  LOCATIONS.map((l) => [l.id, l.name]),
)

/** Initial book stock. countedQty starts null = 未カウント. */
export const INITIAL_ITEMS: CountItem[] = [
  // 売場 A-1 (飲料)
  mk("a1-1", "loc-a1", "天然水 2L", "BV-001", "4901234560011", 48, 78, 110),
  mk("a1-2", "loc-a1", "緑茶 500ml", "BV-002", "4901234560028", 96, 65, 140),
  mk("a1-3", "loc-a1", "炭酸水 500ml", "BV-003", "4901234560035", 72, 58, 120),
  mk("a1-4", "loc-a1", "コーヒー 微糖 185g", "BV-004", "4901234560042", 60, 72, 130),
  // 売場 A-2 (菓子)
  mk("a2-1", "loc-a2", "ポテトチップス うすしお", "SN-001", "4902345670019", 40, 95, 168),
  mk("a2-2", "loc-a2", "チョコビスケット", "SN-002", "4902345670026", 36, 110, 198),
  mk("a2-3", "loc-a2", "あめ アソート", "SN-003", "4902345670033", 24, 130, 230),
  // 売場 B-1 (日用品)
  mk("b1-1", "loc-b1", "ティッシュ 5箱", "DG-001", "4903456780017", 30, 240, 398),
  mk("b1-2", "loc-b1", "トイレットペーパー 12R", "DG-002", "4903456780024", 18, 320, 548),
  mk("b1-3", "loc-b1", "ハンドソープ 詰替", "DG-003", "4903456780031", 27, 150, 268),
  // バックヤード 棚1
  mk("bk1-1", "loc-bk1", "天然水 2L (ケース)", "BV-001C", "4901234560111", 12, 936, 1320),
  mk("bk1-2", "loc-bk1", "緑茶 500ml (ケース)", "BV-002C", "4901234560128", 8, 1560, 3360),
  // バックヤード 棚2
  mk("bk2-1", "loc-bk2", "乾電池 単3 8本", "EL-001", "4904567890015", 22, 280, 498),
  mk("bk2-2", "loc-bk2", "電球 LED 60W相当", "EL-002", "4904567890022", 15, 420, 780),
]

function mk(
  id: string,
  locationId: string,
  name: string,
  sku: string,
  jan: string,
  systemQty: number,
  unitCost: number,
  unitRetail: number,
): CountItem {
  return { id, locationId, name, sku, jan, systemQty, unitCost, unitRetail, countedQty: null, reason: null }
}

// ---- pure reconciliation helpers -------------------------------------------

/** 差異 = 実地カウント − 理論在庫. Returns 0 while 未カウント so it doesn't flag false variance. */
export function variance(item: CountItem): number {
  if (item.countedQty === null) return 0
  return item.countedQty - item.systemQty
}

export function isCounted(item: CountItem): boolean {
  return item.countedQty !== null
}

/** A non-zero variance that has no 差異理由 yet — the thing that blocks 差異確定. */
export function needsReason(item: CountItem): boolean {
  return isCounted(item) && variance(item) !== 0 && item.reason === null
}

export interface StocktakeSummary {
  total: number
  counted: number
  uncounted: number
  /** rows with a non-zero 差異. */
  varianceCount: number
  /** total signed 差異 点数 (Σ variance). */
  varianceUnits: number
  /** Σ |variance| — magnitude of discrepancy in 点. */
  varianceUnitsAbs: number
  /** 差異金額(原価) = Σ(差異 × 原価). Signed; negative = 棚卸減耗. */
  varianceCostAmount: number
  /** 差異金額(売価) = Σ(差異 × 売価). */
  varianceRetailAmount: number
  /** 棚卸資産評価額(原価) = Σ(counted × 原価) over counted rows. */
  inventoryValueCost: number
  /** rows blocking 差異確定 (variance ≠ 0 & no reason). */
  reasonMissingCount: number
}

export function summarize(items: CountItem[]): StocktakeSummary {
  let counted = 0
  let varianceCount = 0
  let varianceUnits = 0
  let varianceUnitsAbs = 0
  let varianceCostAmount = 0
  let varianceRetailAmount = 0
  let inventoryValueCost = 0
  let reasonMissingCount = 0

  for (const item of items) {
    if (isCounted(item)) {
      counted += 1
      inventoryValueCost += (item.countedQty as number) * item.unitCost
      const v = variance(item)
      if (v !== 0) {
        varianceCount += 1
        varianceUnits += v
        varianceUnitsAbs += Math.abs(v)
        varianceCostAmount += v * item.unitCost
        varianceRetailAmount += v * item.unitRetail
        if (item.reason === null) reasonMissingCount += 1
      }
    }
  }

  return {
    total: items.length,
    counted,
    uncounted: items.length - counted,
    varianceCount,
    varianceUnits,
    varianceUnitsAbs,
    varianceCostAmount,
    varianceRetailAmount,
    inventoryValueCost,
    reasonMissingCount,
  }
}

/** Per-location progress (counted / total) for the location nav. */
export function locationProgress(items: CountItem[], locationId: string): { counted: number; total: number } {
  const inLoc = items.filter((i) => i.locationId === locationId)
  return { counted: inLoc.filter(isCounted).length, total: inLoc.length }
}

/** Find an item by scanned code (JAN or SKU, case-insensitive). */
export function findByCode(items: CountItem[], code: string): CountItem | undefined {
  const q = code.trim().toLowerCase()
  if (!q) return undefined
  return items.find((i) => i.jan.toLowerCase() === q || i.sku.toLowerCase() === q)
}

/**
 * 差異金額 threshold (原価, absolute ¥) above which we surface a prominent
 * warning — a real stocktake escalates large 棚卸減耗 to the 店長/本部.
 */
export const VARIANCE_ALERT_THRESHOLD = 20000

"use client"

import * as React from "react"
import {
  IconClipboardList,
  IconBarcode,
  IconArrowUp,
  IconArrowDown,
  IconEqual,
  IconAlertTriangle,
  IconCircleCheck,
  IconLock,
  IconDeviceFloppy,
  IconListSearch,
} from "@tabler/icons-react"
import {
  Card,
  CardHeader,
  CardTitle,
  CardDescription,
  CardContent,
  Badge,
  Button,
  Statistic,
  Separator,
  Alert,
  AlertTitle,
  AlertDescription,
  EditableDataTable,
  RevealSection,
  EmptyState,
  NumberInput,
  Select,
  Input,
  Label,
  Progress,
  Switch,
  formatCurrency,
  formatNumber,
  type EditableColumn,
} from "@gunjo/ui"

import {
  INITIAL_ITEMS,
  LOCATIONS,
  LOCATION_LABEL,
  VARIANCE_REASONS,
  VARIANCE_ALERT_THRESHOLD,
  findByCode,
  isCounted,
  locationProgress,
  needsReason,
  summarize,
  variance,
  type CountItem,
  type StocktakeStatus,
  type VarianceReason,
} from "./stocktake-data"

const yen = (n: number) => formatCurrency(n, { maximumFractionDigits: 0 })
const yenSigned = (n: number) => formatCurrency(n, { maximumFractionDigits: 0, signed: true })
const numSigned = (n: number) => formatNumber(n, { signed: true })

const STATUS_META: Record<
  StocktakeStatus,
  { label: string; variant: "secondary" | "warning" | "info" | "success" }
> = {
  preparing: { label: "準備中", variant: "secondary" },
  counting: { label: "カウント中", variant: "info" },
  reviewing: { label: "差異確認中", variant: "warning" },
  finalized: { label: "確定", variant: "success" },
}

/** 差異 cell: sign + icon + colour + text (never colour alone). */
function VarianceDisplay({ item }: { item: CountItem }) {
  if (!isCounted(item)) {
    return <span className="text-xs text-muted-foreground">未カウント</span>
  }
  const v = variance(item)
  if (v === 0) {
    return (
      <span className="inline-flex items-center justify-end gap-1 font-medium tabular-nums text-success">
        <IconEqual className="h-4 w-4" aria-hidden="true" />
        <span>一致</span>
        <span className="sr-only">差異なし</span>
      </span>
    )
  }
  const positive = v > 0
  const Arrow = positive ? IconArrowUp : IconArrowDown
  return (
    <span
      className={`inline-flex items-center justify-end gap-1 font-semibold tabular-nums ${
        positive ? "text-warning" : "text-destructive"
      }`}
    >
      <Arrow className="h-4 w-4" aria-hidden="true" />
      <span>{numSigned(v)}</span>
      <span className="sr-only">
        {positive ? "理論在庫より多い 棚卸超過" : "理論在庫より少ない 棚卸減耗"}
      </span>
    </span>
  )
}

export default function StocktakeCount() {
  const [items, setItems] = React.useState<CountItem[]>(INITIAL_ITEMS)
  const [activeLoc, setActiveLoc] = React.useState<string>(LOCATIONS[0].id)
  const [status, setStatus] = React.useState<StocktakeStatus>("counting")
  const [varianceOnly, setVarianceOnly] = React.useState(false)
  const [scanCode, setScanCode] = React.useState("")
  const [scanMsg, setScanMsg] = React.useState<{ kind: "ok" | "error"; text: string } | null>(null)
  const [savedAt, setSavedAt] = React.useState<string | null>(null)

  const isFinalized = status === "finalized"
  const editable = !isFinalized

  const summary = React.useMemo(() => summarize(items), [items])

  const overThreshold = Math.abs(summary.varianceCostAmount) >= VARIANCE_ALERT_THRESHOLD
  const progressPct =
    summary.total > 0 ? Math.round((summary.counted / summary.total) * 100) : 0

  // Rows for the active location, optionally filtered to variance-only.
  const visibleRows = React.useMemo(() => {
    let rows = items.filter((i) => i.locationId === activeLoc)
    if (varianceOnly) rows = rows.filter((i) => isCounted(i) && variance(i) !== 0)
    return rows
  }, [items, activeLoc, varianceOnly])

  // ---- mutators -------------------------------------------------------------
  const setCount = (id: string, qty: number | null) =>
    setItems((prev) =>
      prev.map((i) => {
        if (i.id !== id) return i
        const next: CountItem = { ...i, countedQty: qty }
        // Clearing variance (back to a match) drops any now-irrelevant reason.
        if (qty !== null && qty - i.systemQty === 0) next.reason = null
        return next
      }),
    )

  const setReason = (id: string, reason: VarianceReason | null) =>
    setItems((prev) => prev.map((i) => (i.id === id ? { ...i, reason } : i)))

  // ---- scan-to-count --------------------------------------------------------
  const handleScan = (e: React.FormEvent) => {
    e.preventDefault()
    if (!editable) return
    const match = findByCode(items, scanCode)
    if (!match) {
      setScanMsg({ kind: "error", text: `コード「${scanCode}」に一致する商品がありません。` })
      return
    }
    // Jump to that item's location and increment its count by 1.
    setActiveLoc(match.locationId)
    setVarianceOnly(false)
    setItems((prev) =>
      prev.map((i) => (i.id === match.id ? { ...i, countedQty: (i.countedQty ?? 0) + 1 } : i)),
    )
    const newCount = (match.countedQty ?? 0) + 1
    setScanMsg({
      kind: "ok",
      text: `${match.name}（${match.sku}）をカウント +1 → ${newCount}点 / ${LOCATION_LABEL[match.locationId]}`,
    })
    setScanCode("")
  }

  // ---- actions --------------------------------------------------------------
  const handleSave = () => setSavedAt("2026-06-23 15:08")

  const handleLockVariance = () => {
    if (summary.reasonMissingCount > 0) return
    setStatus("reviewing")
  }

  const handleFinalize = () => {
    if (summary.reasonMissingCount > 0 || summary.uncounted > 0) return
    setStatus("finalized")
  }

  // Block reasons (reachable text, surfaced in the action card).
  const lockBlockReason =
    summary.reasonMissingCount > 0
      ? `差異理由が未入力の明細が ${summary.reasonMissingCount} 件あります。`
      : null
  const finalizeBlockReason =
    summary.uncounted > 0
      ? `未カウントの明細が ${summary.uncounted} 件あります。`
      : summary.reasonMissingCount > 0
        ? `差異理由が未入力の明細が ${summary.reasonMissingCount} 件あります。`
        : null

  // ---- grid columns ---------------------------------------------------------
  const columns: EditableColumn<CountItem>[] = [
    {
      id: "product",
      header: "商品 / SKU・JAN",
      minWidth: "12rem",
      cell: (row) => (
        <div className="flex flex-col gap-0.5">
          <span className="font-medium text-foreground">{row.name}</span>
          <span className="text-xs text-muted-foreground tabular-nums">
            {row.sku} · {row.jan}
          </span>
        </div>
      ),
    },
    {
      id: "system",
      header: "理論在庫",
      headerLabel: "理論在庫",
      align: "right",
      width: "6rem",
      cell: (row) => (
        <span className="tabular-nums text-muted-foreground">{formatNumber(row.systemQty)}</span>
      ),
    },
    {
      id: "counted",
      header: "実地カウント数",
      headerLabel: "実地カウント数",
      align: "center",
      width: "9.5rem",
      cell: (row, ctx) => (
        <div className="flex flex-col items-center gap-1">
          <NumberInput
            layout="stepper"
            min={0}
            value={row.countedQty ?? undefined}
            onValueChange={(v) => setCount(row.id, v)}
            disabled={!editable}
            aria-label={ctx.ariaLabel}
            incrementLabel={`${row.name} のカウントを増やす`}
            decrementLabel={`${row.name} のカウントを減らす`}
            className="mx-auto"
          />
          {row.countedQty === null ? (
            <span className="text-[10px] font-medium text-muted-foreground">未カウント</span>
          ) : editable ? (
            <button
              type="button"
              onClick={() => setCount(row.id, null)}
              className="text-[10px] text-muted-foreground underline-offset-2 hover:underline focus-visible:underline"
            >
              未カウントに戻す
            </button>
          ) : null}
        </div>
      ),
    },
    {
      id: "variance",
      header: "差異",
      headerLabel: "差異",
      align: "right",
      width: "7rem",
      cell: (row) => <VarianceDisplay item={row} />,
    },
    {
      id: "reason",
      header: "差異理由",
      headerLabel: "差異理由",
      minWidth: "9rem",
      cell: (row, ctx) => {
        const showReason = isCounted(row) && variance(row) !== 0
        if (!showReason) {
          return <span className="text-xs text-muted-foreground">—</span>
        }
        const missing = needsReason(row)
        return (
          <div className="flex flex-col gap-1">
            <Select
              value={row.reason ?? ""}
              onChange={(e) => setReason(row.id, (e.target.value || null) as VarianceReason | null)}
              disabled={!editable}
              aria-label={ctx.ariaLabel}
              aria-invalid={missing || undefined}
              aria-describedby={missing ? `${ctx.cellId}-err` : undefined}
              className="h-8 text-sm"
            >
              <option value="">理由を選択…</option>
              {VARIANCE_REASONS.map((r) => (
                <option key={r.value} value={r.value}>
                  {r.label}
                </option>
              ))}
            </Select>
            {missing ? (
              <span id={`${ctx.cellId}-err`} className="text-[10px] font-medium text-destructive">
                理由が必要です
              </span>
            ) : null}
          </div>
        )
      },
    },
  ]

  return (
    <main className="mx-auto w-full max-w-6xl px-4 py-6 sm:px-6 lg:py-8">
      {/* ===================== 棚卸ヘッダ ===================== */}
      <header className="mb-6">
        <div className="flex flex-wrap items-start justify-between gap-3">
          <div className="flex items-center gap-2">
            <span className="flex h-9 w-9 shrink-0 items-center justify-center rounded-lg bg-primary-subtle text-primary-subtle-foreground">
              <IconClipboardList className="h-5 w-5" aria-hidden="true" />
            </span>
            <div>
              <h1 className="text-2xl font-bold tracking-tight">実地棚卸</h1>
              <p className="text-sm text-muted-foreground">2026年5月度 月次棚卸</p>
            </div>
          </div>
          <Badge variant={STATUS_META[status].variant} className="h-6 px-3 text-sm">
            <span className="sr-only">棚卸ステータス: </span>
            {STATUS_META[status].label}
          </Badge>
        </div>

        <dl className="mt-4 grid grid-cols-2 gap-x-4 gap-y-2 text-sm sm:grid-cols-4">
          <div>
            <dt className="text-xs text-muted-foreground">対象店舗</dt>
            <dd className="font-medium">新宿東口店</dd>
          </div>
          <div>
            <dt className="text-xs text-muted-foreground">担当者</dt>
            <dd className="font-medium">佐藤 健一</dd>
          </div>
          <div>
            <dt className="text-xs text-muted-foreground">棚卸基準日</dt>
            <dd className="font-medium tabular-nums">2026-05-31</dd>
          </div>
          <div>
            <dt className="text-xs text-muted-foreground">評価方法</dt>
            <dd className="font-medium">原価法（最終仕入）</dd>
          </div>
        </dl>

        {/* overall 進捗 */}
        <div className="mt-4">
          <div className="mb-1 flex items-center justify-between text-sm">
            <span className="font-medium">
              進捗{" "}
              <span className="tabular-nums">
                完了 {summary.counted}/{summary.total}
              </span>
            </span>
            <span className="tabular-nums text-muted-foreground">{progressPct}%</span>
          </div>
          <Progress
            value={summary.counted}
            max={summary.total}
            aria-label={`棚卸進捗 ${summary.counted} / ${summary.total} 完了`}
          />
        </div>
      </header>

      {/* ===================== 差異サマリー ===================== */}
      <section aria-labelledby="summary-heading" className="mb-6">
        <h2 id="summary-heading" className="sr-only">
          差異サマリー
        </h2>
        <div className="grid grid-cols-2 gap-3 sm:grid-cols-4">
          <Statistic
            label="差異点数"
            value={`${summary.varianceCount} 品目`}
            hint={`Σ差異 ${numSigned(summary.varianceUnits)} 点`}
            tone={summary.varianceCount > 0 ? "negative" : "neutral"}
          />
          <Statistic
            label="差異金額（原価）"
            value={yenSigned(summary.varianceCostAmount)}
            trend={
              summary.varianceCostAmount < 0
                ? "down"
                : summary.varianceCostAmount > 0
                  ? "up"
                  : "flat"
            }
            hint={summary.varianceCostAmount < 0 ? "棚卸減耗" : undefined}
          />
          <Statistic
            label="差異金額（売価）"
            value={yenSigned(summary.varianceRetailAmount)}
            tone="neutral"
          />
          <Statistic
            label="棚卸資産（評価額・原価）"
            value={yen(summary.inventoryValueCost)}
            hint={`カウント済 ${summary.counted} 品目`}
            tone="neutral"
          />
        </div>

        {overThreshold ? (
          <Alert variant="warning" className="mt-3">
            <IconAlertTriangle className="h-4 w-4" aria-hidden="true" />
            <AlertTitle>差異金額が基準を超過しています</AlertTitle>
            <AlertDescription>
              差異金額（原価）の絶対値が {yen(VARIANCE_ALERT_THRESHOLD)} を超えています（現在{" "}
              <span className="font-medium tabular-nums">{yenSigned(summary.varianceCostAmount)}</span>
              ）。確定前に店長承認と原因確認が必要です。
            </AlertDescription>
          </Alert>
        ) : null}
      </section>

      <div className="grid grid-cols-1 gap-6 lg:grid-cols-[18rem_minmax(0,1fr)]">
        {/* ===================== LEFT: scan + location nav ===================== */}
        <div className="flex flex-col gap-6">
          {/* バーコード/SKU スキャン入力 */}
          <Card>
            <CardHeader className="p-4 pb-2">
              <CardTitle as="h2" className="flex items-center gap-1.5 text-base">
                <IconBarcode className="h-4 w-4" aria-hidden="true" />
                バーコード / SKU スキャン
              </CardTitle>
              <CardDescription>JAN または SKU を読み取り／入力すると該当商品を +1。</CardDescription>
            </CardHeader>
            <CardContent className="p-4 pt-2">
              <form onSubmit={handleScan} className="flex flex-col gap-2">
                <Label htmlFor="scan-input">商品コード（JAN / SKU）</Label>
                <div className="flex gap-2">
                  <Input
                    id="scan-input"
                    inputMode="numeric"
                    autoComplete="off"
                    placeholder="例: 4901234560011 / BV-001"
                    value={scanCode}
                    onChange={(e) => setScanCode(e.target.value)}
                    disabled={!editable}
                    aria-describedby="scan-feedback"
                  />
                  <Button type="submit" disabled={!editable || scanCode.trim() === ""}>
                    カウント
                  </Button>
                </div>
                {/* live region: announce the matched item / error to SRs. */}
                <p
                  id="scan-feedback"
                  role="status"
                  aria-live="polite"
                  className={`min-h-[1.25rem] text-xs ${
                    scanMsg?.kind === "error" ? "text-destructive" : "text-success"
                  }`}
                >
                  {scanMsg?.text ?? ""}
                </p>
              </form>
            </CardContent>
          </Card>

          {/* ロケーション / 棚 navigation */}
          <Card>
            <CardHeader className="p-4 pb-2">
              <CardTitle as="h2" className="text-base">
                ロケーション / 棚
              </CardTitle>
              <CardDescription>棚ごとのカウント進捗。タップで明細を切替。</CardDescription>
            </CardHeader>
            <CardContent className="p-4 pt-2">
              <nav aria-label="ロケーション選択">
                <ul className="flex flex-col gap-1.5">
                  {LOCATIONS.map((loc) => {
                    const lp = locationProgress(items, loc.id)
                    const done = lp.counted === lp.total
                    const active = loc.id === activeLoc
                    return (
                      <li key={loc.id}>
                        <button
                          type="button"
                          onClick={() => setActiveLoc(loc.id)}
                          aria-current={active ? "true" : undefined}
                          className={`flex w-full items-center justify-between gap-2 rounded-lg border px-3 py-2 text-left text-sm transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 ${
                            active
                              ? "border-primary-border bg-primary-subtle text-primary-subtle-foreground"
                              : "border-border hover:bg-muted"
                          }`}
                        >
                          <span className="flex min-w-0 flex-col">
                            <span className="truncate font-medium">{loc.name}</span>
                            <span className="text-xs text-muted-foreground tabular-nums">
                              棚番 {loc.shelfCode}
                            </span>
                          </span>
                          <span className="flex shrink-0 items-center gap-1.5">
                            {done ? (
                              <IconCircleCheck
                                className="h-4 w-4 text-success"
                                aria-hidden="true"
                              />
                            ) : null}
                            <Badge variant={done ? "success" : "outline"} as="span">
                              <span className="tabular-nums">
                                {lp.counted}/{lp.total}
                              </span>
                              <span className="sr-only">
                                {" "}
                                カウント完了{done ? "（全件）" : ""}
                              </span>
                            </Badge>
                          </span>
                        </button>
                      </li>
                    )
                  })}
                </ul>
              </nav>
            </CardContent>
          </Card>

          {/* ===================== アクション ===================== */}
          <Card>
            <CardHeader className="p-4 pb-2">
              <CardTitle as="h2" className="text-base">
                アクション
              </CardTitle>
            </CardHeader>
            <CardContent className="flex flex-col gap-2 p-4 pt-2">
              {isFinalized ? (
                <Alert variant="success">
                  <IconLock className="h-4 w-4" aria-hidden="true" />
                  <AlertTitle>棚卸確定済み</AlertTitle>
                  <AlertDescription>
                    この棚卸は確定されました。明細は読み取り専用です。
                  </AlertDescription>
                </Alert>
              ) : null}

              <Button
                type="button"
                variant="outline"
                onClick={handleSave}
                disabled={!editable}
              >
                <IconDeviceFloppy className="h-4 w-4" aria-hidden="true" />
                カウント保存
              </Button>
              {savedAt ? (
                <p role="status" className="text-xs text-muted-foreground">
                  最終保存: <span className="tabular-nums">{savedAt}</span>
                </p>
              ) : null}

              <Button
                type="button"
                variant="warning"
                onClick={handleLockVariance}
                disabled={!editable || lockBlockReason !== null}
                aria-describedby={lockBlockReason ? "lock-block" : undefined}
              >
                差異確定（ロック）
              </Button>
              {lockBlockReason ? (
                <p id="lock-block" className="text-xs text-warning">
                  {lockBlockReason}
                </p>
              ) : null}

              <Separator className="my-1" />

              <Button
                type="button"
                variant="primary"
                onClick={handleFinalize}
                disabled={!editable || finalizeBlockReason !== null}
                aria-describedby={finalizeBlockReason ? "finalize-block" : undefined}
              >
                <IconLock className="h-4 w-4" aria-hidden="true" />
                棚卸確定
              </Button>
              {finalizeBlockReason ? (
                <p id="finalize-block" role="status" className="text-xs text-warning">
                  確定できません: {finalizeBlockReason}
                </p>
              ) : !isFinalized ? (
                <p className="text-xs text-success">全件カウント・理由入力済み。確定可能です。</p>
              ) : null}
            </CardContent>
          </Card>
        </div>

        {/* ===================== RIGHT: カウント明細 ===================== */}
        <Card>
          <CardHeader className="gap-3 p-4 pb-2">
            <div className="flex flex-wrap items-center justify-between gap-2">
              <div>
                <CardTitle as="h2" className="text-base">
                  カウント明細 — {LOCATION_LABEL[activeLoc]}
                </CardTitle>
                <CardDescription>
                  理論在庫と実地カウントを照合。差異がある明細は理由が必須です。
                </CardDescription>
              </div>
              <label className="flex items-center gap-2 text-sm">
                <IconListSearch className="h-4 w-4 text-muted-foreground" aria-hidden="true" />
                <span>差異のみ</span>
                <Switch
                  checked={varianceOnly}
                  onCheckedChange={setVarianceOnly}
                  aria-label="差異のある明細だけ表示"
                />
              </label>
            </div>
          </CardHeader>
          <CardContent className="p-4 pt-2">
            {visibleRows.length > 0 ? (
              <EditableDataTable<CountItem>
                columns={columns}
                rows={visibleRows}
                getRowId={(row) => row.id}
                rowLabel={(i) => visibleRows[i]?.name ?? `行 ${i + 1}`}
                getRowError={(row) =>
                  needsReason(row) ? "差異があります。差異理由を選択してください。" : undefined
                }
                caption={
                  <span className="text-xs text-muted-foreground">
                    {LOCATION_LABEL[activeLoc]} の棚卸明細（{visibleRows.length} 品目）
                  </span>
                }
              />
            ) : varianceOnly ? (
              <EmptyState
                headingLevel={3}
                icon={<IconCircleCheck className="h-6 w-6 text-success" aria-hidden="true" />}
                title="差異のある明細はありません"
                description="この棚では理論在庫と実地カウントが一致しています。"
                action={
                  <Button variant="outline" size="sm" onClick={() => setVarianceOnly(false)}>
                    すべての明細を表示
                  </Button>
                }
              />
            ) : (
              <EmptyState
                headingLevel={3}
                icon={<IconClipboardList className="h-6 w-6" aria-hidden="true" />}
                title="この棚に商品がありません"
                description="別のロケーションを選択してください。"
              />
            )}

            {/* per-location reveal: reason still missing somewhere on this shelf */}
            <RevealSection
              open={visibleRows.some(needsReason)}
              label="差異理由の入力が必要です"
              className="mt-4"
            >
              <Alert variant="destructive">
                <IconAlertTriangle className="h-4 w-4" aria-hidden="true" />
                <AlertTitle>差異理由が未入力です</AlertTitle>
                <AlertDescription>
                  差異のある明細には差異理由（
                  {VARIANCE_REASONS.map((r) => r.label).slice(0, 4).join(" / ")} など）の選択が必要です。
                  この棚で未入力: {visibleRows.filter(needsReason).length} 件。
                </AlertDescription>
              </Alert>
            </RevealSection>
          </CardContent>
        </Card>
      </div>
    </main>
  )
}
